int array_any_negative(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      ((__return == 1 &&
        (exists i, 0 <= i && i < n && l[i] < 0)) ||
       (__return == 0 &&
        (forall (i: Z), (0 <= i && i < n) => l[i] >= 0))) &&
      IntArray::full(a, n, l)
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        if (a[i] < 0) {
            return 1;
        }
    }

    return 0;
}

